import { task, wait, logger } from "@trigger.dev/sdk/v3";

const trial_id = "human_in_the_loop_approval__XWqUMs7";

export const approvalTask = task({
  id: `approvalTask-${trial_id}`,
  run: async () => {
    // Step 1: Log that approval is being requested
    logger.log("Requesting approval...");

    // Step 2: Create a wait token with a 1-hour timeout
    const token = await wait.createToken({ timeout: "1h" });

    // Step 3: Log the token ID so it can be used externally to complete the wait
    logger.log(`Wait token ID: ${token.id}`);

    // Step 4: Pause execution and wait for the token to be resolved
    const result = await wait.forToken<{ approved: boolean }>(token.id);

    // Step 5 & 6: Handle the result based on the token output
    if (result.ok && result.output?.approved === true) {
      logger.log("Request approved!");
    } else {
      logger.log("Request rejected.");
    }
  },
});
